(window.webpackJsonp=window.webpackJsonp||[]).push([[353],{622:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[][]}</span> <span class=\\"hljs-variable\\">grid</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> getMaximumGold = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">grid</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> moves=[[<span class=\\"hljs-number\\">-1</span>,<span class=\\"hljs-number\\">0</span>],[<span class=\\"hljs-number\\">1</span>,<span class=\\"hljs-number\\">0</span>],[<span class=\\"hljs-number\\">0</span>,<span class=\\"hljs-number\\">-1</span>],[<span class=\\"hljs-number\\">0</span>,<span class=\\"hljs-number\\">1</span>]]\\n  <span class=\\"hljs-keyword\\">let</span> m=grid.length,n=grid[<span class=\\"hljs-number\\">0</span>].length\\n  <span class=\\"hljs-keyword\\">let</span> visited=<span class=\\"hljs-built_in\\">Array</span>(m).fill().map(<span class=\\"hljs-function\\"><span class=\\"hljs-params\\">()</span>=&gt;</span><span class=\\"hljs-built_in\\">Array</span>(n).fill(<span class=\\"hljs-number\\">0</span>))\\n  <span class=\\"hljs-keyword\\">let</span> uniqId=<span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-keyword\\">let</span> arr=[]\\n  findStart()\\n \\n  <span class=\\"hljs-keyword\\">let</span> collect=<span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-keyword\\">let</span> maxCollect=<span class=\\"hljs-number\\">0</span>\\n   <span class=\\"hljs-keyword\\">if</span>(arr.length===<span class=\\"hljs-number\\">0</span>){\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;m;i++){\\n      <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">0</span>;j&lt;n;j++){\\n        maxCollect+=grid[i][j]\\n      }\\n    }\\n   <span class=\\"hljs-keyword\\">return</span> maxCollect\\n  }\\n  \\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> [x,y] <span class=\\"hljs-keyword\\">of</span> arr){\\n    uniqId++\\n    visited[x][y]=uniqId\\n    dfs([x,y],visited,grid[x][y])\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> maxCollect\\n  \\n  \\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">dfs</span>(<span class=\\"hljs-params\\">[x,y],visited,collect</span>)</span>{\\n     maxCollect=<span class=\\"hljs-built_in\\">Math</span>.max(maxCollect,collect)\\n     <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> [dx,dy] <span class=\\"hljs-keyword\\">of</span> moves){\\n      <span class=\\"hljs-keyword\\">let</span> nx=dx+x\\n      <span class=\\"hljs-keyword\\">let</span> ny=dy+y\\n      <span class=\\"hljs-keyword\\">if</span>(nx&lt;<span class=\\"hljs-number\\">0</span> || ny&lt;<span class=\\"hljs-number\\">0</span> || nx&gt;=m || ny&gt;=n)<span class=\\"hljs-keyword\\">continue</span>\\n      <span class=\\"hljs-keyword\\">if</span>(grid[nx][ny]===<span class=\\"hljs-number\\">0</span>) <span class=\\"hljs-keyword\\">continue</span>\\n      <span class=\\"hljs-keyword\\">if</span>(visited[nx][ny]===uniqId)<span class=\\"hljs-keyword\\">continue</span>\\n       visited[nx][ny]=uniqId\\n       dfs([nx,ny],visited,collect+grid[nx][ny])\\n       visited[nx][ny]=uniqId<span class=\\"hljs-number\\">-1</span>\\n    }\\n  }\\n  \\n  \\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">findStart</span>(<span class=\\"hljs-params\\"></span>)</span>{\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;m;i++){\\n      <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">0</span>;j&lt;n;j++){\\n        <span class=\\"hljs-keyword\\">if</span>(grid[i][j]===<span class=\\"hljs-number\\">0</span>)<span class=\\"hljs-keyword\\">continue</span>\\n        <span class=\\"hljs-keyword\\">let</span> sibl=<span class=\\"hljs-number\\">0</span>\\n        <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> [dx,dy] <span class=\\"hljs-keyword\\">of</span> moves){\\n          <span class=\\"hljs-keyword\\">let</span> nx=dx+i\\n          <span class=\\"hljs-keyword\\">let</span> ny=dy+j\\n          <span class=\\"hljs-keyword\\">if</span>(nx&lt;<span class=\\"hljs-number\\">0</span> || ny&lt;<span class=\\"hljs-number\\">0</span> || nx&gt;=m || ny&gt;=n)<span class=\\"hljs-keyword\\">continue</span>\\n          <span class=\\"hljs-keyword\\">if</span>(grid[nx][ny]!==<span class=\\"hljs-number\\">0</span>)sibl++\\n          <span class=\\"hljs-keyword\\">if</span>(sibl&gt;<span class=\\"hljs-number\\">1</span>)<span class=\\"hljs-keyword\\">break</span>\\n        }\\n        <span class=\\"hljs-keyword\\">if</span>(sibl&gt;<span class=\\"hljs-number\\">1</span>)<span class=\\"hljs-keyword\\">continue</span>\\n        arr.push([i,j,<span class=\\"hljs-number\\">0</span>])\\n      }\\n    }\\n  }\\n};\\n</code></pre>\\n"],"titleSlug":"path-with-maximum-gold","hasThinking":false,"content":"<p>\u4f60\u8981\u5f00\u53d1\u4e00\u5ea7\u91d1\u77ff\uff0c\u5730\u8d28\u52d8\u6d4b\u5b66\u5bb6\u5df2\u7ecf\u63a2\u660e\u4e86\u8fd9\u5ea7\u91d1\u77ff\u4e2d\u7684\u8d44\u6e90\u5206\u5e03\uff0c\u5e76\u7528\u5927\u5c0f\u4e3a&nbsp;<code>m * n</code> \u7684\u7f51\u683c <code>grid</code> \u8fdb\u884c\u4e86\u6807\u6ce8\u3002\u6bcf\u4e2a\u5355\u5143\u683c\u4e2d\u7684\u6574\u6570\u5c31\u8868\u793a\u8fd9\u4e00\u5355\u5143\u683c\u4e2d\u7684\u9ec4\u91d1\u6570\u91cf\uff1b\u5982\u679c\u8be5\u5355\u5143\u683c\u662f\u7a7a\u7684\uff0c\u90a3\u4e48\u5c31\u662f <code>0</code>\u3002</p>\\n\\n<p>\u4e3a\u4e86\u4f7f\u6536\u76ca\u6700\u5927\u5316\uff0c\u77ff\u5de5\u9700\u8981\u6309\u4ee5\u4e0b\u89c4\u5219\u6765\u5f00\u91c7\u9ec4\u91d1\uff1a</p>\\n\\n<ul>\\n\\t<li>\u6bcf\u5f53\u77ff\u5de5\u8fdb\u5165\u4e00\u4e2a\u5355\u5143\uff0c\u5c31\u4f1a\u6536\u96c6\u8be5\u5355\u5143\u683c\u4e2d\u7684\u6240\u6709\u9ec4\u91d1\u3002</li>\\n\\t<li>\u77ff\u5de5\u6bcf\u6b21\u53ef\u4ee5\u4ece\u5f53\u524d\u4f4d\u7f6e\u5411\u4e0a\u4e0b\u5de6\u53f3\u56db\u4e2a\u65b9\u5411\u8d70\u3002</li>\\n\\t<li>\u6bcf\u4e2a\u5355\u5143\u683c\u53ea\u80fd\u88ab\u5f00\u91c7\uff08\u8fdb\u5165\uff09\u4e00\u6b21\u3002</li>\\n\\t<li><strong>\u4e0d\u5f97\u5f00\u91c7</strong>\uff08\u8fdb\u5165\uff09\u9ec4\u91d1\u6570\u76ee\u4e3a <code>0</code> \u7684\u5355\u5143\u683c\u3002</li>\\n\\t<li>\u77ff\u5de5\u53ef\u4ee5\u4ece\u7f51\u683c\u4e2d <strong>\u4efb\u610f\u4e00\u4e2a</strong> \u6709\u9ec4\u91d1\u7684\u5355\u5143\u683c\u51fa\u53d1\u6216\u8005\u662f\u505c\u6b62\u3002</li>\\n</ul>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>grid = [[0,6,0],[5,8,7],[0,9,0]]\\n<strong>\u8f93\u51fa\uff1a</strong>24\\n<strong>\u89e3\u91ca\uff1a</strong>\\n[[0,6,0],\\n [5,8,7],\\n [0,9,0]]\\n\u4e00\u79cd\u6536\u96c6\u6700\u591a\u9ec4\u91d1\u7684\u8def\u7ebf\u662f\uff1a9 -&gt; 8 -&gt; 7\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>grid = [[1,0,7],[2,0,6],[3,4,5],[0,3,0],[9,0,20]]\\n<strong>\u8f93\u51fa\uff1a</strong>28\\n<strong>\u89e3\u91ca\uff1a</strong>\\n[[1,0,7],\\n [2,0,6],\\n [3,4,5],\\n [0,3,0],\\n [9,0,20]]\\n\u4e00\u79cd\u6536\u96c6\u6700\u591a\u9ec4\u91d1\u7684\u8def\u7ebf\u662f\uff1a1 -&gt; 2 -&gt; 3 -&gt; 4 -&gt; 5 -&gt; 6 -&gt; 7\u3002\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 &lt;= grid.length,&nbsp;grid[i].length &lt;= 15</code></li>\\n\\t<li><code>0 &lt;= grid[i][j] &lt;= 100</code></li>\\n\\t<li>\u6700\u591a <strong>25 </strong>\u4e2a\u5355\u5143\u683c\u4e2d\u6709\u9ec4\u91d1\u3002</li>\\n</ul>\\n","title":"1219. \u9ec4\u91d1\u77ff\u5de5","relatedTags":["\u56de\u6eaf\u7b97\u6cd5"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1219"}')}}]);